    settings_stats_scan_title: { fr: 'Scan de vos statistiques', en: 'Stats scan schedule', de: 'Scan Ihrer Statistiken', es: 'Scan de tus estadísticas', ru: 'Сканирование вашей статистики', tr: 'İstatistik tarama' },
    settings_stats_scan_systematic: { fr: 'Un scan systématique a lieu tous les jours à 23h50 (heure locale).', en: 'A systematic scan runs every day at 11:50 PM (local time).', de: 'Ein systematischer Scan läuft täglich um 23:50 Uhr (Ortszeit).', es: 'Un escaneo sistemático se realiza cada día a las 23:50 (hora local).', ru: 'Систематическое сканирование выполняется каждый день в 23:50 (местное время).', tr: 'Her gün 23:50\'de (yerel saat) sistematik bir tarama yapılır.' },
    settings_stats_scan_add_slot: { fr: 'Ajouter un créneau horaire', en: 'Add a time slot', de: 'Zeitfenster hinzufügen', es: 'Añadir un horario', ru: 'Добавить временной слот', tr: 'Zaman dilimi ekle' },
    settings_stats_scan_info_title: { fr: 'Information', en: 'Information', de: 'Information', es: 'Información', ru: 'Информация', tr: 'Bilgi' },
    settings_stats_scan_max_slots: { fr: 'Maximum 4 créneaux.', en: 'Maximum 4 time slots.', de: 'Maximal 4 Zeitfenster.', es: 'Máximo 4 horarios.', ru: 'Максимум 4 слота.', tr: 'En fazla 4 zaman dilimi.' },
    settings_stats_scan_choose_time: { fr: 'Choisissez une heure.', en: 'Choose a time.', de: 'Wählen Sie eine Uhrzeit.', es: 'Elige una hora.', ru: 'Выберите время.', tr: 'Bir saat seçin.' },
    settings_stats_scan_already_added: { fr: 'Ce créneau existe déjà.', en: 'This time slot already exists.', de: 'Dieses Zeitfenster existiert bereits.', es: 'Este horario ya existe.', ru: 'Этот слот уже добавлен.', tr: 'Bu zaman dilimi zaten ekli.' },
    settings_stats_scan_info_body: {
      fr: 'Pour utiliser le scan automatique, renseignez votre compte DarkOrbit dans Mon compte > Compte DarkOrbit.\n\nPour un bon suivi des stats, un scan systématique a lieu tous les jours à 23h50 (heure locale). Cela entraîne une déconnexion du jeu pendant environ 30 secondes.\n\nLes identifiants DarkOrbit sont chiffrés et stockés en local. Aucun utilisateur, pas même le développeur, n\'a accès à ces données.',
      en: 'To use automatic scanning, enter your DarkOrbit account in My account > DarkOrbit account.\n\nFor proper stats tracking, a systematic scan runs every day at 11:50 PM (local time). This causes the game to disconnect for about 30 seconds.\n\nDarkOrbit credentials are encrypted and stored locally. No one, including the developer, has access to this data.',
      de: 'Für den automatischen Scan tragen Sie Ihr DarkOrbit-Konto unter Mein Konto > DarkOrbit-Konto ein.\n\nFür eine zuverlässige Statistik-Aktualisierung läuft täglich um 23:50 Uhr (Ortszeit) ein systematischer Scan. Das führt zu einer Trennung vom Spiel für etwa 30 Sekunden.\n\nDarkOrbit-Zugangsdaten sind verschlüsselt und werden lokal gespeichert. Niemand, auch nicht der Entwickler, hat Zugriff auf diese Daten.',
      es: 'Para usar el escaneo automático, introduce tu cuenta DarkOrbit en Mi cuenta > Cuenta DarkOrbit.\n\nPara un buen seguimiento de estadísticas, se realiza un escaneo sistemático cada día a las 23:50 (hora local). Esto provoca una desconexión del juego durante unos 30 segundos.\n\nLas credenciales de DarkOrbit se cifran y almacenan localmente. Nadie, ni siquiera el desarrollador, tiene acceso a estos datos.',
      ru: 'Для автоматического сканирования укажите аккаунт DarkOrbit в разделе Мой аккаунт > Аккаунт DarkOrbit.\n\nДля корректного учёта статистики систематическое сканирование выполняется каждый день в 23:50 (местное время). Это приводит к отключению от игры примерно на 30 секунд.\n\nУчётные данные DarkOrbit шифруются и хранятся локально. Никто, включая разработчика, не имеет доступа к этим данным.',
      tr: 'Otomatik tarama için Hesabım > DarkOrbit hesabı bölümünde DarkOrbit hesabınızı girin.\n\nİstatistik takibi için her gün 23:50\'de (yerel saat) sistematik bir tarama yapılır. Bu, oyundan yaklaşık 30 saniye bağlantı kesilmesine neden olur.\n\nDarkOrbit kimlik bilgileri şifrelenir ve yerel olarak saklanır. Geliştirici dahil hiç kimsenin bu verilere erişimi yoktur.'
    },
